			FileVO vo = iter.next();
			image = vo.getOrignlFileNm();
		}
	}

	LoginVO user = (LoginVO) EgovUserDetailsHelper.getAuthenticatedUser();

	mainImageVO.setImageId(egovMainImageIdGnrService.getNextStringId());
